INSERT INTO notification_template ( id, name, subject, competent_authority, event_trigger, workflow, text ) VALUES ( nextval('notification_template_seq'), 'FacilityAuditGenericExpirationReminderTemplate', '${workflow} ${workflowTask} (${expirationTime} remaining)', 'ENGLAND', 'Expiration reminder for final review of corrective actions', 'Audit Workflow', 'Dear ${workflowUser},
Facility: ${facilityBusinessId}-${facilityName}
The deadline for the [${workflowTask}](${homeUrl}) of the ${workflow} (reference ${workflowId}) for the above facility is due ${expirationTimeLong}. The task must be completed by ${deadline?date?string(''dd MMMM yyyy'')}.
Please contact your team leader if you are not able to complete the task before this date.
If you think you should not have received this email, you must [contact the CCA Helpdesk](${contactRegulator}).
This is an automatic email - please do not reply to this address.') ;
